using SmartDine.Domain.Enums;using SmartDine.Domain.Interfaces;namespace SmartDine.Order.API.BackgroundServices;/// <summary>/// Background job tß+Ḋ -æß+Öng xß+Ḃ l++ payment hßḊ+t hßḊín.////// VßḊÑn -æß+ü gißḊúi quyßḊ+t:///   PayOS payment link c+Ḋ hiß+çu lß+Ḋc 30 ph+Ḋt. NßḊ+u kh+ích kh+Ḋng qu+Ỳt QR v+á kh+Ḋng c+Ḋ webhook FAIL///   (v+Ḃ dß+Ñ: tho+ít app, mßḊÑt mßḊíng), session bß+ï kßḊḊt ß+ CHECKOUT m+úi m+úi GÇö kh+Ḋng -æßḊ+t th+Ỳm m+Ḋn -æḊḊß+úc,///   kh+Ḋng tßḊío lßḊíi QR -æḊḊß+úc. Background job chßḊíy mß+ùi 5 ph+Ḋt -æß+â detect v+á xß+Ḃ l++ c+íc trḊḊß+ċng hß+úp n+áy.////// H+ánh -æß+Öng khi ph+ít hiß+çn payment PENDING qu+í hßḊín:///   - payment.Status GåÆ EXPIRED///   - session.Status GåÆ ACTIVE (unblock -æßḊ+t m+Ḋn, cho ph+Ỳp retry thanh to+ín)////// C+ích -æ-âng k++: builder.Services.AddHostedService&lt;PaymentExpiryJob&gt;() trong Program.cs.////// LḊḊu ++: IUnitOfWork l+á scoped service, BackgroundService l+á singleton.///   GåÆ PhßḊúi tßḊío scope mß+ḃi mß+ùi lßḊẃn chßḊíy qua IServiceScopeFactory (kh+Ḋng inject trß+Ḋc tißḊ+p)./// </summary>public class PaymentExpiryJob : BackgroundService{    private static readonly TimeSpan RunInterval = TimeSpan.FromMinutes(5);    private static readonly TimeSpan PaymentLinkTtl = TimeSpan.FromMinutes(30);    private readonly IServiceScopeFactory _scopeFactory;    private readonly ILogger<PaymentExpiryJob> _logger;    public PaymentExpiryJob(IServiceScopeFactory scopeFactory, ILogger<PaymentExpiryJob> logger)    {        _scopeFactory = scopeFactory;        _logger = logger;    }    /// <summary>    /// V+Ḋng lßḊ+p ch+Ḃnh: delay RunInterval GåÆ chßḊíy expiry check GåÆ lßḊ+p lßḊíi.    /// Delay -æßḊẃu ti+Ỳn trḊḊß+ḃc khi chßḊíy -æß+â tr+ính xung -æß+Öt l+Ḋc app khß+i -æß+Öng.    /// </summary>    protected override async Task ExecuteAsync(CancellationToken stoppingToken)    {        _logger.LogInformation("PaymentExpiryJob started GÇö runs every {Interval} minutes.", RunInterval.TotalMinutes);        while (!stoppingToken.IsCancellationRequested)        {            await Task.Delay(RunInterval, stoppingToken);            try            {                await ExpireStalePaymentsAsync(stoppingToken);            }            catch (Exception ex) when (ex is not OperationCanceledException)            {                // Log lß+ùi nhḊḊng tißḊ+p tß+Ñc chßḊíy GÇö kh+Ḋng -æß+â 1 lßḊẃn lß+ùi dß+Ẅng to+án bß+Ö job                _logger.LogError(ex, "PaymentExpiryJob encountered an error during expiry check.");            }        }    }    /// <summary>    /// Qu+Ỳt tßḊÑt cßḊú payment PENDING tßḊío trḊḊß+ḃc cutoff GåÆ mark EXPIRED GåÆ unblock session.    ///    /// Ai d+Ḋng: ExecuteAsync (nß+Öi bß+Ö background job).    /// Side effect: session.Status GåÆ ACTIVE cho ph+Ỳp kh+ích retry thanh to+ín.    /// </summary>    private async Task ExpireStalePaymentsAsync(CancellationToken ct)    {        using var scope = _scopeFactory.CreateScope();        var uow = scope.ServiceProvider.GetRequiredService<IUnitOfWork>();        var cutoff = DateTime.UtcNow - PaymentLinkTtl;        var stalePayments = await uow.Payments.GetPendingOlderThanAsync(cutoff);        if (!stalePayments.Any()) return;        _logger.LogInformation("PaymentExpiryJob: found {Count} expired payments to process.", stalePayments.Count);        foreach (var payment in stalePayments)        {            payment.PaymentStatus = PaymentStatus.EXPIRED;            await uow.Payments.UpdateAsync(payment);            // Revert session vß+ü ACTIVE nßḊ+u -æang bß+ï kh+Ḋa ß+ CHECKOUT            if (payment.Session?.Status == DiningSessionStatus.CHECKOUT)            {                payment.Session.Status = DiningSessionStatus.ACTIVE;                await uow.DiningSessions.UpdateAsync(payment.Session);                _logger.LogInformation(                    "PaymentExpiryJob: session {SessionId} reverted to ACTIVE (payment {InvoiceId} expired).",                    payment.SessionId, payment.InvoiceId);            }        }        await uow.SaveChangesAsync(ct);    }}